// Note: requires C++26 std::execution (P2300).
// Shown as a spec-based example — not compiled.
#include <execution>
#include <print>

int main() {
    // just(42) is a sender that immediately completes with the value 42.
    // sync_wait blocks the current thread until the sender completes,
    // returning optional<tuple<int>>.
    auto result = std::execution::sync_wait(
        std::execution::just(42)
    );

    // *result is tuple<int>{42}
    std::println("{}", std::get<0>(*result)); // prints: 42
}

// Three sender types — three completion channels.
// Shown as a spec-based example.
#include <execution>
#include <print>

int main() {
    // Channel 1: set_value(42)
    auto val_sender = std::execution::just(42);
    auto r1 = std::execution::sync_wait(val_sender);
    // r1 == optional<tuple<int>>{42}

    // Channel 2: set_error(exception_ptr)
    auto err_sender = std::execution::just_error(
        std::make_exception_ptr(std::runtime_error{"fail"}));
    // sync_wait will rethrow the exception_ptr

    // Channel 3: set_stopped()
    auto stop_sender = std::execution::just_stopped();
    auto r3 = std::execution::sync_wait(stop_sender);
    // r3 == std::nullopt  (cancellation — not an error, just no result)

    std::println("value: {}",   std::get<0>(*r1)); // 42
    std::println("stopped: {}", !r3.has_value());   // true
}

// then() takes a sender and a function, returns a new sender.
// The chain is built lazily — nothing runs until sync_wait.
#include <execution>
#include <print>

int main() {
    // Each | builds a new sender without starting anything.
    auto pipeline =
        std::execution::just(10)
        | std::execution::then([](int x) { return x * 3; })
        | std::execution::then([](int x) { return x + 2; });

    // sync_wait launches the entire graph in one shot.
    auto result = std::execution::sync_wait(std::move(pipeline));
    std::println("{}", std::get<0>(*result)); // (10 * 3) + 2 == 32
}

