#include <execution>
#include <iostream>
#include <thread>

int main() {
    namespace ex = std::execution;

    ex::run_loop loop;
    auto sch = loop.get_scheduler();

    // Launch the chain asynchronously
    // (in real code loop.run() is called on a separate thread)
    std::jthread worker([&loop]{ loop.run(); });

    auto result = ex::sync_wait(
        ex::schedule(sch)                      // transfer to loop's context
        | ex::then([](){ return 42; })         // runs on loop
        | ex::then([](int x){ return x * 2; }) // also on loop
    );

    loop.finish();

    // *result == tuple{84}
    auto [v] = *result;
    std::cout << v << '\n';  // 84
}

