#include <execution>
#include <iostream>
#include <chrono>
#include <thread>

int compute_a() {
    // simulate work
    std::this_thread::sleep_for(std::chrono::milliseconds{100});
    return 6;
}

int compute_b() {
    std::this_thread::sleep_for(std::chrono::milliseconds{80});
    return 7;
}

int main() {
    namespace ex = std::execution;

    std::execution::thread_pool pool{2};  // two worker threads
    auto sch = pool.get_scheduler();

    // Both computations start simultaneously:
    // compute_a() and compute_b() run in parallel.
    auto result = ex::sync_wait(
        ex::when_all(
            ex::schedule(sch) | ex::then([]{ return compute_a(); }),
            ex::schedule(sch) | ex::then([]{ return compute_b(); })
        )
    );

    // result = std::optional<std::tuple<int, int>>
    // Order matches argument order to when_all,
    // not the order in which they finished.
    auto [r1, r2] = *result;
    std::cout << r1 << " * " << r2 << " = " << r1 * r2 << '\n';
    // Expected output: 6 * 7 = 42
}

#include <execution>
#include <iostream>
#include <stdexcept>

int main() {
    namespace ex = std::execution;

    std::execution::thread_pool pool{2};
    auto sch = pool.get_scheduler();

    // First sender always errors.
    // Second is a "long" computation that should receive
    // stop_requested and complete via set_stopped.
    auto result = ex::sync_wait(
        ex::when_all(
            ex::schedule(sch)
                | ex::then([]() -> int {
                    throw std::runtime_error{"computation A failed"};
                    return 0;
                }),
            ex::schedule(sch)
                | ex::then([]() -> int {
                    // In real code, check stop_token here
                    // and return early. For illustration we just return.
                    return 99;
                })
        )
    );

    // when_all completed via set_error — result == std::nullopt
    // and the exception is rethrown when sync_wait exits.
    // The block below is never reached:
    if (result) {
        auto [r1, r2] = *result;
        std::cout << r1 << ' ' << r2 << '\n';
    } else {
        std::cout << "result unavailable (cancelled)\n";
    }
}
// To catch the error, wrap sync_wait in try/catch:
// try { ex::sync_wait(...); }
// catch (const std::runtime_error& e) { std::cerr << e.what(); }

#include <execution>
#include <iostream>

int expensive_query() {
    // Imagine: a network request, file parse, etc.
    return 100;
}

int main() {
    namespace ex = std::execution;

    // A plain sender can be connected only once.
    // split makes it copyable — both copies share
    // the same underlying computation.
    auto shared_source = ex::split(
        ex::just(0) | ex::then([]([[maybe_unused]] int) {
            return expensive_query();
        })
    );

    // Build two independent continuations from one source:
    auto pipeline_a = shared_source | ex::then([](int v) { return v + 1; });
    auto pipeline_b = shared_source | ex::then([](int v) { return v * 2; });

    // Run both in parallel via when_all:
    auto result = ex::sync_wait(
        ex::when_all(
            std::move(pipeline_a),
            std::move(pipeline_b)
        )
    );

    // expensive_query() is called exactly once.
    // The result (100) is available to both continuations.
    auto [a, b] = *result;
    std::cout << "a = " << a << '\n';  // 101
    std::cout << "b = " << b << '\n';  // 200
}

