#include <execution>
#include <system_error>
#include <iostream>

// Simulate an operation that may return std::error_code.
// just_error creates a sender that completes via set_error.
auto fetch_data(bool fail) {
    namespace ex = std::execution;
    if (fail) {
        // Error type is std::error_code, NOT exception_ptr.
        return ex::just_error(
            std::make_error_code(std::errc::connection_refused)
        );
    }
    return ex::just(std::make_error_code({}))  // "no error", for type symmetry
        | ex::then([](std::error_code) { return 42; });
}

int main() {
    namespace ex = std::execution;

    // upon_error: fn takes std::error_code, returns an int value.
    // The lambda MUST accept std::error_code — any other signature is a compile error.
    auto pipeline =
        fetch_data(/*fail=*/true)
        | ex::upon_error([](std::error_code ec) -> int {
            std::cerr << "Error: " << ec.message() << '\n';
            return -1;  // default value in place of the error
        });

    auto result = ex::sync_wait(std::move(pipeline));
    // The set_error channel was converted to set_value(-1),
    // so result holds std::optional<std::tuple<int>>.
    if (result) {
        std::cout << "Result: " << std::get<0>(*result) << '\n';
    }
}

#include <execution>
#include <system_error>
#include <iostream>
#include <string>

// Simulate two sources: the primary always fails.
auto primary_source() {
    namespace ex = std::execution;
    return ex::just_error(
        std::make_error_code(std::errc::no_such_file_or_directory)
    );
}

auto fallback_source() {
    namespace ex = std::execution;
    // The fallback returns a string result.
    return ex::just(std::string{"data from cache"});
}

int main() {
    namespace ex = std::execution;

    // let_error: fn returns a NEW SENDER, not a value.
    // This is the key difference from upon_error.
    auto pipeline =
        primary_source()
        | ex::let_error([](std::error_code ec) {
            if (ec == std::errc::no_such_file_or_directory) {
                std::cerr << "Primary source unavailable, using cache\n";
                return fallback_source();  // <-- return a new sender
            }
            // For any other error — propagate it.
            return ex::just_error(ec);
        });

    auto result = ex::sync_wait(std::move(pipeline));
    if (result) {
        std::cout << "Got: " << std::get<0>(*result) << '\n';
    }
}

#include <execution>
#include <stop_token>  // std::stop_source, std::stop_token (C++20)
#include <iostream>
#include <thread>
#include <chrono>

// A long-running "operation" that could check a stop_token.
// In real code this would be a custom sender with a built-in stop check.
auto long_operation() {
    namespace ex = std::execution;
    // For this example we just return a value via just.
    // A real custom sender would call get_stop_token(receiver) internally.
    return ex::just(std::string{"result of long operation"});
}

int main() {
    namespace ex = std::execution;

    std::stop_source cancel_source;  // external cancellation source

    // stop_when ties the pipeline to an external stop_token.
    // If cancel_source.request_stop() is called, the pipeline
    // receives stop_requested and finishes via set_stopped.
    auto cancelable_pipeline = ex::stop_when(
        long_operation(),
        cancel_source.get_token()
    );

    // In a real scenario, cancellation might come from a UI button:
    // std::thread([&]{
    //     std::this_thread::sleep_for(std::chrono::milliseconds{50});
    //     cancel_source.request_stop();
    // }).detach();

    // Here we do NOT cancel — the pipeline should complete normally.
    auto result = ex::sync_wait(std::move(cancelable_pipeline));

    if (result) {
        std::cout << "Completed: " << std::get<0>(*result) << '\n';
    } else {
        // If cancel_source.request_stop() had been called,
        // sync_wait would return std::nullopt (set_stopped channel).
        std::cout << "Operation was cancelled\n";
    }
}

