exercises.explanation:
On line 12 (`return backup();`) `upon_error` expects `fn` to return a **value**, but `backup()` returns a **sender**. The compiler will either reject this (if the types are incompatible) or treat the sender object as the value — meaning the string `"fallback"` will never be produced; instead the pipeline will carry a sender object as its value. The correct adaptor for "error → new sender" is `let_error`, not `upon_error`:
```cpp
| ex::let_error([](std::error_code) {
      return backup();
  })
```

examples.code:
// Requires C++26 std::execution (P2300).
// Shown as a spec-based example — not compiled.
#include <execution>
#include <print>
#include <stdexcept>

// Imagine these are real async operations:
auto positive_path(int x) {
    // Returns a sender that produces x * 2
    return std::execution::just(x * 2);
}

auto negative_path() {
    // Returns a sender that signals an error
    return std::execution::just_error(
        std::make_exception_ptr(
            std::runtime_error{"negative input not allowed"}
        )
    );
}

int main() {
    namespace ex = std::execution;

    // let_value: fn returns a NEW SENDER, not a plain int.
    // Which sender depends on the value — that is the point.
    auto pipeline =
        ex::just(42)
        | ex::let_value([](int x) {
            // fn must return a sender:
            if (x > 0)
                return positive_path(x);   // → just(84)
            else
                return negative_path();    // → just_error(...)
        });

    // With just(42), the positive branch runs → 84.
    auto result = ex::sync_wait(std::move(pipeline));
    std::println("{}", std::get<0>(*result)); // 84

    // If we started with just(-1), negative_path() would fire
    // and sync_wait would rethrow the runtime_error.
}

// Demonstrates let_error: fn receives the error and returns a sender.
// Unlike upon_error (fn returns a plain value),
// let_error's fn can launch a full async operation.
#include <execution>
#include <print>
#include <stdexcept>

// Simulates an async fallback query (returns a sender):
auto query_fallback_service() {
    return std::execution::just(-1); // fallback value
}

int main() {
    namespace ex = std::execution;

    // Primary sender: immediately signals an error.
    auto primary = ex::just_error(
        std::make_exception_ptr(std::runtime_error{"primary failed"})
    );

    auto pipeline =
        std::move(primary)
        | ex::let_error([](std::exception_ptr) {
            // fn receives the error, returns a new sender.
            // Here we launch an async fallback.
            // (In production this could be a network request sender.)
            return query_fallback_service();
        });

    // The error is intercepted; the fallback sender runs in its place.
    auto result = ex::sync_wait(std::move(pipeline));
    std::println("{}", std::get<0>(*result)); // -1

    // Contrast: upon_error would require the fn to return -1 directly.
    // let_error allows the fn to return query_fallback_service()
    // — an async operation, not a plain value.
}

// Conceptual illustration of the zero-allocation guarantee.
// All operation states are inline — no heap allocation.
#include <execution>
#include <print>

int main() {
    namespace ex = std::execution;

    // Each | step wraps the previous sender in a new type.
    // The compiler knows the complete type at compile time.
    auto pipeline =
        ex::just(1)                             // JustSender<int>
        | ex::then([](int x){ return x + 1; }) // ThenSender<JustSender<int>, L1>
        | ex::then([](int x){ return x * 3; }) // ThenSender<ThenSender<...>, L2>
        | ex::let_value([](int x) {             // LetValueSender<..., L3>
            return ex::just(x - 1);
          });

    // connect() returns an object whose type encodes ALL four states.
    // Its size is known at compile time. It lives on the stack below:
    auto op = ex::connect(std::move(pipeline), /* some receiver */ 0);
    // sizeof(op) is known at compile time — no new, no shared_ptr.
    // All four sub-states are packed inline inside op.

    // In practice, sync_wait does connect + start for us:
    auto result = ex::sync_wait(
        ex::just(1)
        | ex::then([](int x){ return x + 1; })  // 2
        | ex::then([](int x){ return x * 3; })  // 6
        | ex::let_value([](int x) {
            return ex::just(x - 1);              // 5
          })
    );
    std::println("{}", std::get<0>(*result)); // 5

    // For comparison: each std::async call allocates
    // a shared_ptr control block on the heap.
    // A chain of 4 async calls = 4 heap allocations.
    // This pipeline = 0 heap allocations.
}

